import{_ as a,c as s,o as i,a5 as t}from"./chunks/framework.CgT1UzWm.js";const m=JSON.parse('{"title":"DEFINE_PARAM Annotation","titleTemplate":"NpgsqlRest","description":"Define virtual HTTP parameters that are not bound to the PostgreSQL command. Used for custom parameter placeholders, claim mapping, and HTTP request matching in SQL file endpoints.","frontmatter":{"outline":[2,3],"title":"DEFINE_PARAM Annotation","titleTemplate":"NpgsqlRest","description":"Define virtual HTTP parameters that are not bound to the PostgreSQL command. Used for custom parameter placeholders, claim mapping, and HTTP request matching in SQL file endpoints.","head":[["meta",{"name":"keywords","content":"npgsqlrest define_param, virtual parameter, sql file parameter, claim mapping parameter, custom parameter placeholder"}],["meta",{"property":"og:title","content":"NpgsqlRest DEFINE_PARAM Annotation"}],["meta",{"property":"og:description","content":"Define virtual HTTP parameters that are not bound to the PostgreSQL command."}],["meta",{"property":"og:type","content":"article"}]]},"headers":[],"relativePath":"annotations/define-param.md","filePath":"annotations/define-param.md"}'),n={name:"annotations/define-param.md"};function r(l,e,p,o,d,h){return i(),s("div",null,e[0]||(e[0]=[t(`<h1 id="define-param" tabindex="-1">DEFINE_PARAM <a class="header-anchor" href="#define-param" aria-label="Permalink to &quot;DEFINE_PARAM&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Also known as</p><p><code>define_param</code> (with or without <code>@</code> prefix)</p></div><p>Define HTTP parameters that are <strong>not</strong> bound to the PostgreSQL command. These virtual parameters exist in the HTTP request (query string or JSON body) but do not correspond to any <code>$N</code> positional parameter in the SQL query.</p><p>This is useful for SQL file endpoints where you need HTTP parameters for:</p><ul><li><strong>Custom parameter placeholders</strong> — parameters that feed into annotation placeholders like <code>{format}</code> without being part of the SQL</li><li><strong>Claim mapping</strong> — auto-filling parameters from authenticated user claims without referencing them in the query</li><li><strong>HTTP request matching</strong> — parameters that affect endpoint behavior without participating in the database query</li></ul><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@define_param name</span></span>
<span class="line"><span>@define_param name type</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><ul><li><code>name</code> — the HTTP parameter name</li><li><code>type</code> — optional PostgreSQL type (default: <code>text</code>)</li></ul><h2 id="custom-parameter-placeholders" tabindex="-1">Custom Parameter Placeholders <a class="header-anchor" href="#custom-parameter-placeholders" aria-label="Permalink to &quot;Custom Parameter Placeholders&quot;">​</a></h2><p>Pass HTTP parameters that control endpoint behavior without referencing them in SQL:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- sql/users_report.sql</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @define_param format text</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @table_format = {format}</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @param $1 department_id</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, email </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> department_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p><code>GET /api/users-report?department_id=5&amp;format=html_table</code></p><p>The <code>format</code> parameter feeds into the <code>@table_format</code> annotation via the <code>{format}</code> placeholder, selecting the output format (JSON, HTML table, Excel, etc.) without being part of the SQL query. Without <code>@define_param</code>, there would be no <code>format</code> parameter in the endpoint — the <code>{format}</code> placeholder would have nothing to resolve.</p><h2 id="claim-mapping" tabindex="-1">Claim Mapping <a class="header-anchor" href="#claim-mapping" aria-label="Permalink to &quot;Claim Mapping&quot;">​</a></h2><p>Auto-fill a parameter from the authenticated user&#39;s claims without including it in the SQL query:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- sql/user_dashboard.sql</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @authorize</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @user_parameters</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @define_param _user_id</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_dashboard_data;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p>Here <code>_user_id</code> is created as a virtual parameter that maps to the <code>name_identifier</code> claim (via standard <a href="/annotations/user-parameters.html">User Parameters</a> claim mapping). The authenticated user&#39;s ID is injected automatically — but unlike <code>@param</code>, this parameter doesn&#39;t correspond to any <code>$N</code> in the SQL. The query itself doesn&#39;t filter by user — the virtual parameter exists solely for the claim mapping mechanism.</p><p>This is different from using <code>@param</code> with <code>@user_parameters</code>:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- This uses @param — $1 IS in the SQL query</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @authorize</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @user_parameters</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @param $1 _user_id</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p>Use <code>@define_param</code> when the parameter shouldn&#39;t appear in the SQL at all. Use <code>@param</code> when you need the value both as a claim-mapped parameter and as a query parameter.</p><h2 id="default-type" tabindex="-1">Default Type <a class="header-anchor" href="#default-type" aria-label="Permalink to &quot;Default Type&quot;">​</a></h2><p>If no type is specified, the parameter defaults to <code>text</code>:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- These are equivalent:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @define_param _user_id</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @define_param _user_id text</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p>Specify a type when needed:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @define_param _user_id integer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./param.html">PARAM</a> — rename, retype, and configure parameters that are bound to SQL (<code>$N</code>)</li><li><a href="./user-parameters.html">USER_PARAMETERS</a> — enable claim-to-parameter mapping</li><li><a href="./custom-parameters.html">Custom Parameters</a> — custom key-value annotation settings with <code>{param}</code> placeholders</li><li><a href="/config/sql-file-source.html">SQL File Source configuration</a> — enable and configure SQL file endpoints</li></ul>`,27)]))}const u=a(n,[["render",r]]);export{m as __pageData,u as default};
